"use client";

import Link from "next/link";
import { motion } from "framer-motion";
import { ArrowRight } from "lucide-react";

interface Condition {
  slug: string;
  title: string;
  shortDescription: string;
  icon: string;
}

interface ConditionCardProps {
  condition: Condition;
  index?: number;
}

export function ConditionCard({
  condition,
  index = 0,
}: ConditionCardProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ delay: index * 0.08 }}
    >
      <Link
        href={`/conditions/${condition.slug}`}
        className="glass-panel p-6 sm:p-8 rounded-3xl block hover:bg-foreground/5 transition-colors duration-300 group"
      >
        <div className="flex justify-between items-start mb-3">
          <h3 className="font-medium text-base sm:text-lg text-foreground">
            {condition.title}
          </h3>
          <ArrowRight
            size={16}
            className="text-muted group-hover:text-foreground transition-colors shrink-0 mt-1"
          />
        </div>
        <p className="text-muted text-xs sm:text-sm leading-relaxed">
          {condition.shortDescription}
        </p>
      </Link>
    </motion.div>
  );
}
